/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Exports the contents of a grid (using the selected order and filters) to a PDF file. LoadWWPContext.Call(&Context)
Do 'LoadGridState'
&Title = "Lista de Cadastro de Receitas Produto"
//Report Template Source Header &AppName = "DVelop Software Solutions" &Phone = !"+1 550 8923" &Mail = !"info@mail.com" &Website = !"http://www.web.com" &AddressLine1 = !"French Boulevard 2859" &AddressLine2 = !"Downtown" &AddressLine3 = !"Paris, France" Print printTitle End Footer &PageInfo = "Page: " + &Page.ToString().Trim() &DateInfo = "Date: " + &Today.ToFormattedString() Print printFooter End
Do 'PrintFilters'
Do 'PrintColumnTitles'
Do 'PrintData'
Do 'PrintFooter'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Sub 'PrintFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If not &ProRef.IsEmpty() print printBlockFilterProRef EndIf If not &ProNom.IsEmpty() print printBlockFilterProNom EndIf If not &ProTipDef.IsEmpty() &FilterProTipDefValueDescription = &ProTipDef.EnumerationDescription()
print printBlockFilterProTipDef EndIf If not &ProTipCus.IsEmpty() &FilterProTipCusValueDescription = &ProTipCus.EnumerationDescription()
print printBlockFilterProTipCus EndIf If not &ProSts.IsEmpty() &FilterProStsValueDescription = &ProSts.EnumerationDescription()
print printBlockFilterProSts EndIf If not &ProStsRec.IsEmpty() &FilterProStsRecValueDescription = '' Do Case Case &ProStsRec.ToString().Trim() = !"S" &FilterProStsRecValueDescription = "Válida"
Case &ProStsRec.ToString().Trim() = !"N" &FilterProStsRecValueDescription = "Inválida"
EndCase
print printBlockFilterProStsRec EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintColumnTitles'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
print printBlockBeforeGrid print printBlockLines_titles
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintData'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
For each order EmpCod ProNom when &OrderedBy = 1 order ProRef when &OrderedBy = 2 AND &OrderedDsc = False order (ProRef) when &OrderedBy = 2 AND &OrderedDsc = True order ProNom when &OrderedBy = 3 AND &OrderedDsc = False order (ProNom) when &OrderedBy = 3 AND &OrderedDsc = True order ProEmbUnd when &OrderedBy = 4 AND &OrderedDsc = False order (ProEmbUnd) when &OrderedBy = 4 AND &OrderedDsc = True order ProTipCus when &OrderedBy = 5 AND &OrderedDsc = False order (ProTipCus) when &OrderedBy = 5 AND &OrderedDsc = True order ProTipDef when &OrderedBy = 6 AND &OrderedDsc = False order (ProTipDef) when &OrderedBy = 6 AND &OrderedDsc = True order ProAtuEst when &OrderedBy = 7 AND &OrderedDsc = False order (ProAtuEst) when &OrderedBy = 7 AND &OrderedDsc = True
using DSWWProdutoReceita(&ProRef, &ProNom, &ProTipDef, &ProTipCus, &ProSts, &ProStsRec) &ProTipCusDescription = ProTipCus.EnumerationDescription() If Not ProTipDef.IsEmpty() &ProTipDefDescription = ProTipDef.EnumerationDescription() Else &ProTipDefDescription.SetEmpty() Endif
Do 'BeforePrintLine' print printBlockLines_data Do 'AfterPrintLine' EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(!"WWProdutoReceitaGridState") = !"" &GridState.FromXml(LoadGridState.Udp(!"WWProdutoReceitaGridState")) Else &GridState.FromXml(&Session.Get(!"WWProdutoReceitaGridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"PROREF" &ProRef.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PRONOM" &ProNom.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PROTIPDEF" &ProTipDef.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PROTIPCUS" &ProTipCus.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PROSTS" &ProSts.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PROSTSREC" &ProStsRec.FromString(&GridStateFilterValue.Value) EndCase EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'BeforePrintLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'AfterPrintLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintFooter'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub

	/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */

Output_file("ExportReportWWProdutoReceita","PDF");

